/** Params grouped by effect family (built once at module load). */
export const VP4_PARAMS_BY_FAMILY: Readonly<Record<string, readonly Param[]>> = (() => {
  const map: Record<string, Param[]> = {};
  for (const p of VP4_PARAMS) {
    (map[p.family] ??= []).push(p);
  }
  return Object.freeze(map);
})();

